export interface Usuario {
  id: number;
  username: string;
  rol: 'ADMIN' | 'MESERO' | 'CLIENTE';
}

export interface LoginRequest {
  username: string;
  password: string;
}

export interface LoginResponse {
  token: string;
  usuario: Usuario;
  message: string;
}

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:8080/api';

// Mock de usuarios para desarrollo
const MOCK_USUARIOS = [
  { id: 1, username: 'admin', password: 'admin123', rol: 'ADMIN' as const },
  { id: 2, username: 'mesero1', password: 'mesero123', rol: 'MESERO' as const },
  { id: 3, username: 'cliente1', password: 'cliente123', rol: 'CLIENTE' as const },
];

class AuthService {
  private static instance: AuthService;
  private token: string | null = null;
  private usuario: Usuario | null = null;

  constructor() {
    this.token = localStorage.getItem('auth_token');
    const usuarioData = localStorage.getItem('auth_usuario');
    if (usuarioData) {
      this.usuario = JSON.parse(usuarioData);
    }
  }

  static getInstance(): AuthService {
    if (!AuthService.instance) {
      AuthService.instance = new AuthService();
    }
    return AuthService.instance;
  }

  // Verificar si el backend está disponible
  private async isBackendAvailable(): Promise<boolean> {
    try {
      const response = await fetch(`${API_BASE_URL}/health`, {
        method: 'GET',
        timeout: 3000 as any
      });
      return response.ok;
    } catch {
      return false;
    }
  }

  async login(credentials: LoginRequest): Promise<LoginResponse> {
    const backendAvailable = await this.isBackendAvailable();
    
    if (backendAvailable) {
      return this.loginWithBackend(credentials);
    } else {
      console.warn('Backend no disponible, usando mock data');
      return this.loginWithMock(credentials);
    }
  }

  private async loginWithBackend(credentials: LoginRequest): Promise<LoginResponse> {
    try {
      const response = await fetch(`${API_BASE_URL}/auth/login`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(credentials),
      });

      if (!response.ok) {
        const error = await response.json().catch(() => ({ message: 'Error de conexión' }));
        throw new Error(error.message || 'Error en el login');
      }

      const data: LoginResponse = await response.json();
      
      this.token = data.token;
      this.usuario = data.usuario;
      
      localStorage.setItem('auth_token', data.token);
      localStorage.setItem('auth_usuario', JSON.stringify(data.usuario));

      return data;
    } catch (error) {
      console.error('Error en login con backend:', error);
      throw error;
    }
  }

  private async loginWithMock(credentials: LoginRequest): Promise<LoginResponse> {
    // Simular delay de red
    await new Promise(resolve => setTimeout(resolve, 1000));

    // Buscar usuario en mock data
    const usuario = MOCK_USUARIOS.find(
      u => u.username === credentials.username && u.password === credentials.password
    );

    if (!usuario) {
      throw new Error('Credenciales inválidas');
    }

    // Generar token mock
    const token = `mock_token_${Date.now()}_${usuario.id}`;
    
    const usuarioSinPassword = {
      id: usuario.id,
      username: usuario.username,
      rol: usuario.rol
    };

    // Guardar en memoria y localStorage
    this.token = token;
    this.usuario = usuarioSinPassword;
    
    localStorage.setItem('auth_token', token);
    localStorage.setItem('auth_usuario', JSON.stringify(usuarioSinPassword));

    return {
      token,
      usuario: usuarioSinPassword,
      message: 'Login exitoso (modo desarrollo)'
    };
  }

  logout(): void {
    this.token = null;
    this.usuario = null;
    localStorage.removeItem('auth_token');
    localStorage.removeItem('auth_usuario');
  }

  isAuthenticated(): boolean {
    return !!this.token && !!this.usuario;
  }

  isAdmin(): boolean {
    return this.usuario?.rol === 'ADMIN';
  }

  getUsuario(): Usuario | null {
    return this.usuario;
  }

  getToken(): string | null {
    return this.token;
  }

  // Helper para hacer requests autenticados
  async authenticatedRequest<T>(
    endpoint: string, 
    options: RequestInit = {}
  ): Promise<T> {
    if (!this.token) {
      throw new Error('No hay token de autenticación');
    }

    // Si es un token mock, usar datos mock
    if (this.token.startsWith('mock_token_')) {
      return this.mockRequest<T>(endpoint, options);
    }

    // Request real al backend
    const response = await fetch(`${API_BASE_URL}${endpoint}`, {
      ...options,
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${this.token}`,
        ...options.headers,
      },
    });

    if (response.status === 401) {
      this.logout();
      throw new Error('Sesión expirada');
    }

    if (!response.ok) {
      throw new Error(`HTTP error! status: ${response.status}`);
    }

    return response.json();
  }

  // Mock para requests cuando no hay backend
  private async mockRequest<T>(endpoint: string, options: RequestInit = {}): Promise<T> {
    await new Promise(resolve => setTimeout(resolve, 500));

    // Mock data para diferentes endpoints
    if (endpoint === '/usuarios' && (!options.method || options.method === 'GET')) {
      return MOCK_USUARIOS.map(u => ({
        id: u.id,
        username: u.username,
        rol: u.rol
      })) as unknown as T;
    }

    if (endpoint === '/usuarios' && options.method === 'POST') {
      const body = JSON.parse(options.body as string);
      const newUser = {
        id: Date.now(),
        username: body.username,
        rol: body.rol
      };
      return newUser as T;
    }

    if (endpoint.startsWith('/usuarios/') && options.method === 'DELETE') {
      return {} as T;
    }

    // Para otros endpoints, retornar mock genérico
    return {} as T;
  }
}

export const authService = AuthService.getInstance();
